const fs = require('fs');
const items = $input.all();
const folder = items[0].json.folder;
const basePath = 'C:/Users/veeramani/desktop/playwright-mcp/tests';
const fullPath = `${basePath}/${folder}`;

// 🚀 FULL RUN: No slice limit, runs all 21+ files
