const { execSync } = require('child_process');
const item = $input.item.json;

const product = item.product;
const filename = item.filename;
const testPath = item.testPath;
const cmd = `npx playwright test "${testPath}" --reporter=json`;
const cwd = 'C:/Users/veeramani/desktop/playwright-mcp';

const startTime = new Date();
let stdout = '';
let stderr = '';
let exitCode = 0;

try {
  stdout = execSync(cmd, { cwd, stdio: 'pipe', timeout: 300000 }).toString();
} catch (e) {
  exitCode = e.status || 1;
  stdout = (e.stdout || '').toString();
  stderr = (e.stderr || e.message || '').toString();
}

const endTime = new Date();
const duration = ((endTime - startTime) / 1000).toFixed(2);

let testCases = [];
let stats = { total: 0, passed: 0, failed: 0, skipped: 0 };
let reportSummary = '';

try {
  const jsonMatch = stdout.match(/\{[\s\S]*\}/);
  if (jsonMatch) {
    const jsonData = JSON.parse(jsonMatch[0]);
    if (jsonData.stats) {
      stats.passed = jsonData.stats.expected || 0;
      stats.failed = jsonData.stats.unexpected || 0;
      stats.skipped = jsonData.stats.skipped || 0;
      stats.total = stats.passed + stats.failed + stats.skipped;
    }

    if (jsonData.suites) {
      jsonData.suites.forEach(suite => {
        if (suite.specs) {
          suite.specs.forEach(spec => {
            spec.tests.forEach(test => {
              const result = test.results && test.results[0];
              testCases.push({
                title: spec.title || 'Untitled Test',
                status: result ? result.status : 'unknown',
                duration: result ? result.duration : 0
              });
            });
          });
        }
      });
    }
    reportSummary = testCases.map(tc => `${tc.status === 'passed' ? '✅' : '❌'} ${tc.title}`).join('\n');
  }
} catch (e) {
  reportSummary = exitCode === 0 ? '✅ All tests passed' : '❌ Test execution failed';
}

return {
  json: {
    ...item,
    exitCode: exitCode,
    stdout: (stdout || '').substring(0, 1000),
    stderr: (stderr || '').substring(0, 1000),
    status: exitCode === 0 ? 'passed' : 'failed',
    duration: `${duration}s`,
    timestamp: new Date().toISOString(),
    testCases: testCases,
    stats: stats,
    reportSummary: reportSummary
  }
};

