const fs = require('fs');
const path = require('path');
const resultsDir = 'C:/Users/veeramani/.gemini/antigravity/scratch/Automation Workflow/temp_results';
const lockFile = path.join(resultsDir, 'summary.lock');

if (fs.existsSync(lockFile)) return { json: { alreadySent: true } };
if (fs.readdirSync(resultsDir).length === 0) return { json: { alreadySent: false, totalFiles: 0 } };
fs.writeFileSync(lockFile, 'locked');

const files = fs.readdirSync(resultsDir).filter(f => f.startsWith('test_') && f.endsWith('.json'));
let totalFiles = 0, passedFiles = 0, totalCases = 0, passedCases = 0, totalDuration = 0, product = 'ERP';
let failures = [];
let allTestCases = [];

files.forEach(file => {
  try {
    const data = JSON.parse(fs.readFileSync(path.join(resultsDir, file)));
    totalFiles++; 
    if (data.exitCode === 0) passedFiles++;
    else failures.push(data.filename);

    if (data.testCases && Array.isArray(data.testCases)) {
      allTestCases = allTestCases.concat(data.testCases.map(tc => ({ ...tc, file: data.filename })));
    }

    const fileTotal = (data.stats ? data.stats.total : 0);
    const filePassed = (data.stats ? data.stats.passed : 0);

    totalCases += (fileTotal || 0);
    passedCases += (filePassed || 0);

    product = data.product || product;
    const d = parseFloat(data.duration || '0');
    if (!isNaN(d)) totalDuration += d;
  } catch (e) {}
});

if (totalCases < passedCases) totalCases = passedCases;
const failedCases = Math.max(0, totalCases - passedCases);

let testCaseReport = allTestCases.map(tc => `${tc.status === 'passed' ? '✅' : '❌'} ${tc.title} (${tc.file})`).join('\n');
if (testCaseReport.length > 2000) testCaseReport = testCaseReport.substring(0, 1997) + '...';

return { json: {
  alreadySent: false, 
  totalFiles,
  passedFiles,
  totalCases,
  passedCases,
  failedCases,
  failedFilesList: failures.length > 0 ? failures.join(', ') : 'None',
  product, 
  successRate: totalCases > 0 ? ((passedCases/totalCases)*100).toFixed(2) + '%' : '0.00%',
  totalDuration: totalDuration.toFixed(2) + 's',
  testCaseReport: testCaseReport || 'No test cases recorded.',
  timestamp: new Date().toLocaleString('en-IN', { timeZone: 'Asia/Kolkata' })
} };

