<table><thead><tr><th>Test Title</th><th>File</th><th>Status</th></tr></thead><tbody>${rows}</tbody></table></div></body></html>`;

const binaryData = await this.helpers.prepareBinaryData(Buffer.from(htmlContent), `Full_Suite_Report_${Date.now()}.html`, 'text/html');
